// 1. MEMOIZE — cache expensive computation
function memoize(fn) {
  const cache = new Map();
  return function(...args) {
    const key = JSON.stringify(args);
    if (cache.has(key)) return cache.get(key);
    const result = fn.apply(this, args);
    cache.set(key, result);
    return result;
  };
}

const expensiveCalc = memoize((n) => {
  console.log(`computing ${n}...`);
  return n * n;
});
console.log(expensiveCalc(5)); // computing 5...  → 25
console.log(expensiveCalc(5)); //                → 25 (cached, no log)

// 2. ONCE — runs only on the first call
function once(fn) {
  let called = false;
  let result;
  return function(...args) {
    if (!called) { called = true; result = fn.apply(this, args); }
    return result;
  };
}

const initDB = once(() => { console.log('DB connected'); return 'connection'; });
initDB(); // 'DB connected'
initDB(); // silence — runs nothing again

// 3. PARTIAL APPLICATION — pre-fill arguments
function partial(fn, ...presetArgs) {
  return function(...laterArgs) {
    return fn(...presetArgs, ...laterArgs);
  };
}

const add = (a, b, c) => a + b + c;
const add10 = partial(add, 10);
console.log(add10(5, 3)); // 18

// 4. REACT HOOK ANALOGY — useState uses closures internally
function useState(initial) {
  let state = initial;
  const getState = () => state;
  const setState = (newVal) => { state = newVal; };
  return [getState, setState];
}

const [count, setCount] = useState(0);
setCount(5);
console.log(count()); // 5

